import React, { useState, useEffect, useRef } from 'react';
import api from '../services/api';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';

function Relatorios() {
  const [filtros, setFiltros] = useState({ cliente_id: '', data_inicio: '', data_fim: '', categoria_id: '' });
  const [mostrarTempo, setMostrarTempo] = useState(false);
  const [resultados, setResultados] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const relatorioRef = useRef();

  useEffect(() => {
    const load = async () => {
      const [cli, cat] = await Promise.all([api.get('/clientes'), api.get('/categorias')]);
      setClientes(cli.data);
      setCategorias(cat.data);
    };
    load();
  }, []);

  const gerarRelatorio = async () => {
    const res = await api.get('/relatorios', { params: filtros });
    setResultados(res.data.dados || []);
  };

  const gerarPDF = async () => {
    const element = relatorioRef.current;
    if (!element) return;
    const canvas = await html2canvas(element, { scale: 2, backgroundColor: '#ffffff' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('landscape', 'mm', 'a4');
    const imgWidth = 290;
    const imgHeight = (canvas.height * imgWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 10, 10, imgWidth, imgHeight);
    const pdfBlob = pdf.output('blob');
    const pdfUrl = URL.createObjectURL(pdfBlob);
    window.open(pdfUrl); // ou download automático
    // Para enviar ao WhatsApp, geramos um link para compartilhar
    const link = document.createElement('a');
    link.href = pdfUrl;
    link.download = 'relatorio_servicos.pdf';
    link.click();
    return pdfBlob;
  };

  const enviarWhatsApp = async () => {
    const blob = await gerarPDF(); // gera e baixa, mas vamos usar o blob para compartilhar
    if (!blob) return;
    // Criar um arquivo temporário para compartilhar (não é possível enviar diretamente pelo navegador sem API)
    // Uma alternativa é gerar o PDF e abrir o WhatsApp Web com uma mensagem pré-definida.
    const url = URL.createObjectURL(blob);
    const mensagem = `Relatório de serviços concluídos - ${new Date().toLocaleDateString()}`;
    // Abrir WhatsApp Web com texto (o usuário anexará manualmente)
    window.open(`https://wa.me/?text=${encodeURIComponent(mensagem)}`, '_blank');
    alert('PDF gerado! Após abrir o WhatsApp, anexe o arquivo que foi baixado automaticamente.');
  };

  const totalGeral = () => resultados.reduce((acc, r) => acc + (r.total_servico || 0), 0).toFixed(2);
  const totalTempo = () => {
    if (!mostrarTempo) return null;
    const seg = resultados.reduce((acc, r) => acc + (r.tempo_acumulado_segundos || 0), 0);
    return `${Math.floor(seg/3600)}h ${Math.floor((seg%3600)/60)}min`;
  };

  return (
    <div>
      <h2>Relatórios de Serviços Concluídos</h2>
      <div className="filtros-container">
        <select onChange={e => setFiltros({...filtros, cliente_id: e.target.value})}>
          <option value="">Todos clientes</option>
          {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
        </select>
        <input type="date" onChange={e => setFiltros({...filtros, data_inicio: e.target.value})} />
        <input type="date" onChange={e => setFiltros({...filtros, data_fim: e.target.value})} />
        <select onChange={e => setFiltros({...filtros, categoria_id: e.target.value})}>
          <option value="">Todos serviços</option>
          {categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
        </select>
        <label><input type="checkbox" checked={mostrarTempo} onChange={e => setMostrarTempo(e.target.checked)} /> Mostrar tempo</label>
        <button className="btn btn-primary" onClick={gerarRelatorio}>Filtrar</button>
        {resultados.length > 0 && (
          <>
            <button className="btn btn-success" onClick={gerarPDF}>📄 Baixar PDF</button>
            <button className="btn btn-success" onClick={enviarWhatsApp}>📱 Enviar para WhatsApp</button>
          </>
        )}
      </div>

      <div ref={relatorioRef} className="table-responsive" style={{ background: 'white', borderRadius: '24px', padding: '1rem' }}>
        <table style={{ width: '100%' }}>
          <thead>
            <tr><th>Cliente</th><th>Data</th><th>Equipamento</th><th>Serviço Realizado</th><th>Tipo</th><th>Valor Serviço</th><th>Deslocamento</th><th>Total</th>{mostrarTempo && <th>Tempo</th>}</tr>
          </thead>
          <tbody>
            {resultados.map(os => (
              <tr key={os.id}>
                <td>{os.cliente_nome}</td><td>{new Date(os.data_conclusao).toLocaleDateString()}</td>
                <td>{os.equipamento} {os.modelo}</td><td>{os.servico_realizado || '—'}</td>
                <td>{os.tipo_atendimento}</td><td>R$ {parseFloat(os.preco_final).toFixed(2)}</td>
                <td>R$ {parseFloat(os.valor_deslocamento).toFixed(2)}</td>
                <td><strong>R$ {os.total_servico.toFixed(2)}</strong></td>
                {mostrarTempo && <td>{os.tempo_formatado}</td>}
              </tr>
            ))}
          </tbody>
          {resultados.length > 0 && (
            <tfoot>
              <tr style={{ background: '#f8f9fa', fontWeight: 'bold' }}>
                <td colSpan="7" style={{ textAlign: 'right' }}>Total Geral:</td>
                <td>R$ {totalGeral()}</td>
                {mostrarTempo && <td>{totalTempo()}</td>}
              </tr>
            </tfoot>
          )}
        </table>
        {resultados.length === 0 && <p style={{ textAlign: 'center', padding: 30 }}>Nenhum serviço concluído no período.</p>}
      </div>
    </div>
  );
}

export default Relatorios;
